    {
      "id": "regulatory_compliance",
      "name": "Regulatory Compliance",
      "human": {
        "description": "Regulatory compliance is the ability to design, build, and operate systems that meet pharmaceutical regulations such as GxP, 21 CFR Part 11, EU Annex 11, GDPR, and HIPAA. It demands rigor in documentation, validation, traceability, and auditability throughout the software lifecycle.",
        "proficiencyDescriptions": {
