pathway:capability:delivery#9089e749:
{
  "id": "delivery",
  "name": "Delivery",
  "emojiIcon": "🚀",
  "ordinalRank": 1,
  "description": "Delivery covers the end-to-end execution of validated software solutions for pharmaceutical workflows, from problem discovery through prototyping, integration, and full-stack implementation. It emphasizes shipping regulated, reliable systems that translate scientific and operational needs into production value.",
  "professionalResponsibilities": {
    "awareness": "Observes delivery activities, completes well-scoped tasks under guidance, and learns the team's tools, regulated SDLC, and validation expectations.",
    "foundational": "Delivers small features end-to-end with mentorship, follows established patterns, and contributes to integrations and prototypes within a single component.",
    "working": "Independently delivers medium-complexity features across the stack, integrates with internal and external systems, and validates solutions against scientific and business requirements.",
    "practitioner": "Leads delivery of complex, cross-system initiatives, drives discovery through prototyping into production, and sets technical direction for integration and full-stack architecture.",
    "expert": "Shapes multi-team delivery strategy, anticipates platform-wide risks across regulated pharma systems, and establishes patterns adopted broadly for discovery, prototyping, integration, and full-stack engineering."
  },
  "managementResponsibilities": {
    "awareness": "Learns how delivery flows through the team, observes planning rituals, and understands how regulated pharma constraints shape engineering work.",
    "foundational": "Coordinates small delivery efforts, removes immediate blockers for engineers, and ensures basic delivery hygiene around discovery, prototyping, and integration.",
    "working": "Manages delivery for a team, balances discovery and execution, and ensures full-stack and integration work meets quality and compliance expectations.",
    "practitioner": "Directs delivery across multiple teams or programs, aligns discovery and prototyping investments with portfolio outcomes, and matures integration and full-stack practices.",
    "expert": "Sets organization-wide delivery strategy, governs discovery-to-production pipelines for regulated products, and develops leaders who scale full-stack and integration capabilities."
  },
  "skills": [
    {
      "id": "data_integration",
      "name": "Data Integration",
      "human": {
        "description": "Data integration is the practice of moving, transforming, and reconciling data across pharmaceutical systems such as LIMS, ELN, MES, CTMS, and analytics platforms. It requires careful handling of schemas, identifiers, validation, and regulatory traceability so that downstream consumers can trust the data.",
